import React, { useState, useRef } from 'react';
import toast from 'react-hot-toast';
import { createProduct, getProductByBarcode, createPurchase, getPurchases } from '../services/api';

const fmt = n => `₹${parseFloat(n || 0).toFixed(2)}`;

function CreateProductModal({ onClose, onCreated }) {
  const [form, setForm] = useState({ barcode: '', name: '', selling_price: '', auto_barcode: false });
  const [loading, setLoading] = useState(false);

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const handleSubmit = async e => {
    e.preventDefault();
    if (!form.name) { toast.error('Product name required'); return; }
    setLoading(true);
    try {
      const payload = { name: form.name, selling_price: parseFloat(form.selling_price) || 0 };
      if (!form.auto_barcode && form.barcode) payload.barcode = form.barcode;
      const { data } = await createProduct(payload);
      toast.success(`Product "${data.name}" created! Barcode: ${data.barcode}`);
      onCreated(data);
      onClose();
    } catch (err) {
      toast.error(err.response?.data?.barcode?.[0] || 'Failed to create product');
    } finally { setLoading(false); }
  };

  return (
    <div className="modal-overlay">
      <div className="modal">
        <h2>📦 Create New Product</h2>
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Product Name *</label>
            <input autoFocus value={form.name} onChange={e => set('name', e.target.value)} placeholder="e.g. Chocolate Cake" />
          </div>
          <div className="form-group">
            <label style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <input type="checkbox" checked={form.auto_barcode} onChange={e => set('auto_barcode', e.target.checked)}
                style={{ width: 'auto', marginRight: 4 }} />
              Auto-generate Barcode
            </label>
          </div>
          {!form.auto_barcode && (
            <div className="form-group">
              <label>Barcode (leave blank to auto-generate)</label>
              <input value={form.barcode} onChange={e => set('barcode', e.target.value)} placeholder="Scan or enter barcode" style={{ fontFamily: 'var(--mono)' }} />
            </div>
          )}
          <div className="form-group">
            <label>Selling Price (₹)</label>
            <input type="number" step="0.01" value={form.selling_price} onChange={e => set('selling_price', e.target.value)} placeholder="0.00" />
          </div>
          <div style={{ display: 'flex', gap: 10 }}>
            <button type="submit" className="btn btn-primary" style={{ flex: 1, justifyContent: 'center' }} disabled={loading}>
              {loading ? 'Creating…' : '✓ Create Product'}
            </button>
            <button type="button" className="btn btn-secondary" onClick={onClose}>Cancel</button>
          </div>
        </form>
      </div>
    </div>
  );
}

function AddPurchaseForm() {
  const [barcode, setBarcode] = useState('');
  const [product, setProduct] = useState(null);
  const [form, setForm] = useState({ mrp: '', purchase_price: '', tax: '', quantity: '' });
  const [loading, setLoading] = useState(false);

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const handleBarcodeScan = async e => {
    if (e.key !== 'Enter') return;
    if (!barcode.trim()) return;
    try {
      const { data } = await getProductByBarcode(barcode.trim());
      setProduct(data);
      toast.success(`Found: ${data.name}`);
    } catch {
      toast.error('Product not found. Create it first.');
    }
  };

  const handleSubmit = async e => {
    e.preventDefault();
    if (!product) { toast.error('Scan a product first'); return; }
    if (!form.quantity || parseInt(form.quantity) < 1) { toast.error('Enter valid quantity'); return; }
    setLoading(true);
    try {
      await createPurchase({
        product: product.id,
        mrp: parseFloat(form.mrp) || 0,
        purchase_price: parseFloat(form.purchase_price) || 0,
        tax: parseFloat(form.tax) || 0,
        quantity: parseInt(form.quantity),
      });
      toast.success(`Purchase recorded! Stock updated for ${product.name}`);
      setProduct(null);
      setBarcode('');
      setForm({ mrp: '', purchase_price: '', tax: '', quantity: '' });
    } catch { toast.error('Failed to record purchase'); }
    finally { setLoading(false); }
  };

  return (
    <div className="card">
      <h2 style={{ fontSize: 17, fontWeight: 700, marginBottom: 20 }}>📥 Record Purchase</h2>
      <div className="form-group">
        <label>Scan Product Barcode</label>
        <input value={barcode} onChange={e => setBarcode(e.target.value)} onKeyDown={handleBarcodeScan}
          placeholder="Scan barcode and press Enter…" style={{ fontFamily: 'var(--mono)' }} />
      </div>
      {product && (
        <div style={{ background: 'var(--bg3)', border: '1px solid var(--green)', borderRadius: 'var(--radius)', padding: 14, marginBottom: 16 }}>
          <div style={{ display: 'flex', gap: 16, alignItems: 'center' }}>
            <div style={{ flex: 1 }}>
              <div style={{ fontWeight: 700, color: 'var(--text)' }}>{product.name}</div>
              <div style={{ fontSize: 12, color: 'var(--text3)', fontFamily: 'var(--mono)' }}>{product.barcode}</div>
            </div>
            <div style={{ fontSize: 12, color: 'var(--text3)' }}>
              Current Stock: <strong style={{ color: 'var(--green)' }}>{product.stock_quantity}</strong>
            </div>
          </div>
        </div>
      )}
      <form onSubmit={handleSubmit}>
        <div className="form-row">
          <div className="form-group">
            <label>MRP (₹)</label>
            <input type="number" step="0.01" value={form.mrp} onChange={e => set('mrp', e.target.value)} placeholder="0.00" />
          </div>
          <div className="form-group">
            <label>Purchase Price (₹)</label>
            <input type="number" step="0.01" value={form.purchase_price} onChange={e => set('purchase_price', e.target.value)} placeholder="0.00" />
          </div>
          <div className="form-group">
            <label>Tax (%)</label>
            <input type="number" step="0.01" value={form.tax} onChange={e => set('tax', e.target.value)} placeholder="0" />
          </div>
          <div className="form-group">
            <label>Quantity</label>
            <input type="number" value={form.quantity} onChange={e => set('quantity', e.target.value)} placeholder="0" />
          </div>
        </div>
        <button type="submit" className="btn btn-primary" disabled={!product || loading} style={{ justifyContent: 'center', minWidth: 180 }}>
          {loading ? 'Saving…' : '✓ Record Purchase'}
        </button>
      </form>
    </div>
  );
}

export default function Purchase() {
  const [showCreate, setShowCreate] = useState(false);

  return (
    <div>
      <div className="page-header">
        <h1>📦 Purchase</h1>
        <button className="btn btn-primary" onClick={() => setShowCreate(true)}>+ Create Product</button>
      </div>
      <AddPurchaseForm />
      {showCreate && <CreateProductModal onClose={() => setShowCreate(false)} onCreated={() => {}} />}
    </div>
  );
}
